SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS `ai_knowledge` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `question` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标准问题',
  `answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标准答案',
  `category` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '干洗咨询' COMMENT '知识分类',
  `keywords` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '匹配关键词',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：0-停用 1-启用',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序',
  `hit_count` int NOT NULL DEFAULT 0 COMMENT '命中次数',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_ai_knowledge_status` (`status` ASC) USING BTREE,
  INDEX `idx_ai_knowledge_category` (`category` ASC) USING BTREE
) ENGINE = InnoDB DEFAULT CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI客服知识库' ROW_FORMAT = Dynamic;

CREATE TABLE IF NOT EXISTS `ai_chat_message` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NULL DEFAULT NULL COMMENT '用户ID，游客为空',
  `question` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户问题',
  `answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'AI回答',
  `source_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'KNOWLEDGE/OPENAI/ZHIPU/FALLBACK',
  `matched_knowledge_id` bigint NULL DEFAULT NULL COMMENT '命中的知识库ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_ai_chat_user` (`user_id` ASC) USING BTREE,
  INDEX `idx_ai_chat_knowledge` (`matched_knowledge_id` ASC) USING BTREE
) ENGINE = InnoDB DEFAULT CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI客服问答日志' ROW_FORMAT = Dynamic;

INSERT INTO `ai_knowledge` (`id`, `question`, `answer`, `category`, `keywords`, `status`, `sort_order`, `hit_count`, `created_at`, `updated_at`) VALUES
(1, '羽绒服干洗需要多久？', '羽绒服一般需要5-7天左右。旺季、厚款、长款或有顽固污渍时可能顺延1-2天；下单时可以在备注里说明取衣时间要求。', '洗护周期', '羽绒服,多久,周期,取衣,加急', 1, 1, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(2, '西装干洗怎么收费？', '西装上衣69元起，上衣+裤子套装99元起，三件套含马甲129元起。最终价格会根据规格和实际材质确认。', '价格规格', '西装,套装,价格,收费,马甲', 1, 2, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(3, '羊绒大衣可以干洗吗？', '羊绒、羊毛大衣建议专业干洗。我们会先检查洗标和污渍，再进行预处理、低温清洗、整形熨烫，减少缩水和变形风险。', '洗护方式', '羊绒大衣,羊毛大衣,干洗,缩水,变形', 1, 3, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(4, '皮衣护理需要几天？', '皮衣清洁保养通常需要7-10天。皮质补色、上油、局部修复等项目需要师傅评估后确认时间。', '洗护周期', '皮衣,护理,补色,上油,多久', 1, 4, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(5, '可以上门取衣吗？', '支持上门取衣。你可以在下单时选择地址并填写联系电话，门店会按预约时段联系取件；部分偏远区域可能需要人工确认服务范围。', '取送服务', '上门,取衣,取件,地址,预约时段', 1, 5, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(6, '洗完可以送回家吗？', '支持洗后送回。订单完成后可选择到店自取或配送到家，配送时间以门店实际安排和用户地址为准。', '取送服务', '送回,配送,到家,自取,订单完成', 1, 6, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(7, '衣服有油渍能洗掉吗？', '油渍会先做局部预处理，再进入清洗流程。新鲜油渍成功率更高，陈年油渍、染色类污渍无法保证完全去除。', '污渍处理', '油渍,污渍,去渍,陈年污渍,预处理', 1, 7, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(8, '衣服染色了怎么办？', '染色问题建议先拍照并送店评估。串色、褪色、深浅色互染需要专业判断，部分面料只能淡化，不能保证恢复原样。', '污渍处理', '染色,串色,褪色,恢复,评估', 1, 8, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(9, '真丝衣物可以洗吗？', '真丝衣物可以护理，但需要看洗标和染色牢度。建议选择真丝专项清洗，避免高温、强搓和长时间浸泡。', '洗护方式', '真丝,丝绸,洗标,褪色,精洗', 1, 9, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(10, '鞋子清洗需要多久？', '运动鞋、帆布鞋一般3-7天；皮鞋护理约3-5天；雪地靴和长靴通常5-8天。特殊材质或补色会延长。', '洗护周期', '鞋子,运动鞋,皮鞋,雪地靴,长靴,多久', 1, 10, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(11, '窗帘清洗怎么收费？', '普通窗帘按米计价，约25元/米起；加厚、遮光、纱帘价格不同。下单前建议备注尺寸和层数，门店会核价。', '价格规格', '窗帘,按米,价格,遮光帘,纱帘', 1, 11, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(12, '床单被罩多久能洗好？', '床单、被罩、四件套一般4-6天左右，遇到大件集中清洗或梅雨天气可能顺延。', '洗护周期', '床单,被罩,四件套,大件,周期', 1, 12, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(13, '可以加急洗衣吗？', '部分普通衣物支持加急，需要门店确认排单和面料情况。羽绒服、皮衣、奢侈品护理通常不建议强行加急。', '订单服务', '加急,当天取,排单,普通衣物,门店确认', 1, 13, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(14, '订单怎么取消？', '未取件或未开始清洗的订单可以申请取消；已开始清洗的订单需要联系门店确认，可能无法全额退款。', '订单服务', '取消订单,退款,未取件,已清洗', 1, 14, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(15, '衣服洗坏了怎么处理？', '请第一时间保留衣物、订单和照片，在订单售后或门店联系工作人员。平台会根据收衣检查记录、洗标和实际情况协助处理。', '售后服务', '洗坏,赔付,售后,投诉,订单', 1, 15, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(16, '衣物丢失怎么办？', '若怀疑衣物丢失，请提供订单号、衣物照片和取送记录。门店会核查交接记录、清点单和监控信息后给出处理方案。', '售后服务', '丢失,找不到,订单号,清点,赔付', 1, 16, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(17, '哪些衣物不适合普通水洗？', '羊绒羊毛、真丝、皮革、含涂层面料、结构复杂礼服、易褪色深色衣物不建议普通水洗，应按洗标选择专业干洗或精洗。', '洗护方式', '不适合水洗,羊毛,真丝,皮革,礼服,洗标', 1, 17, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(18, '洗衣前需要自己处理口袋吗？', '建议下单前取出口袋内现金、票据、耳机、钥匙等物品。门店也会做基础检查，但贵重和隐私物品请提前自查。', '下单提醒', '口袋,贵重物品,票据,钥匙,下单提醒', 1, 18, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(19, '有会员折扣吗？', '服务页展示“会员再享9折”的项目，可在下单结算时查看实际优惠。不同活动、商品和服务可能适用规则不同。', '优惠活动', '会员,折扣,优惠,9折,活动', 1, 19, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(20, '怎么查看我的订单？', '登录后进入“我的订单”即可查看订单状态、付款信息、取送进度和售后入口。', '订单服务', '我的订单,订单状态,付款,进度,登录', 1, 20, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(21, '干洗和水洗有什么区别？', '干洗主要使用专业溶剂处理油性污渍，适合羊毛、羊绒、西装等易变形面料；水洗更适合棉麻、运动服、床品等耐水洗衣物。', '洗护方式', '干洗,水洗,区别,溶剂,面料', 1, 21, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(22, '毛毯清洗怎么收费？', '毛毯按尺寸和厚度收费，小毛毯60元起，中毛毯80元起，大毛毯100元起，加厚款会加收护理费。', '价格规格', '毛毯,尺寸,厚度,大件,价格', 1, 22, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(23, '玩偶公仔可以清洗吗？', '毛绒玩偶、公仔可以清洗，小号25元起。带电子元件、发声装置或特殊填充物的玩偶需先说明，门店会评估是否可洗。', '洗护方式', '玩偶,公仔,毛绒,电子元件,填充物', 1, 23, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(24, '洗护用品商城卖什么？', '商城提供洗衣液、柔顺剂、衣物除菌液、去渍笔、防串色片、鞋类护理剂等洗护用品，可和干洗服务一起下单。', '商城商品', '洗护用品,洗衣液,柔顺剂,去渍笔,防串色片', 1, 24, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(25, '去渍笔适合什么场景？', '去渍笔适合临时处理咖啡、酱汁、口红等小面积新鲜污渍。贵重衣物、真丝羊绒和大面积污渍建议交给门店处理。', '商城商品', '去渍笔,咖啡,酱汁,口红,新鲜污渍', 1, 25, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(26, '如何选择附近门店？', '进入“附近门店”可以查看门店位置、联系方式和服务范围。建议优先选择距离近、营业中且支持取送的门店。', '门店服务', '附近门店,地址,电话,营业,服务范围', 1, 26, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(27, '收衣时会检查衣物吗？', '会检查。门店会核对衣物数量、明显污渍、破损、纽扣拉链和洗标信息；特殊情况建议拍照备注，避免后续争议。', '下单提醒', '收衣检查,污渍,破损,纽扣,洗标', 1, 27, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(28, '深色衣服会掉色吗？', '深色衣物存在褪色风险，尤其是牛仔、真丝、棉麻和新衣。门店会做基础判断，但无法完全避免面料本身染色牢度问题。', '风险提示', '深色,掉色,褪色,牛仔,染色牢度', 1, 28, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(29, '可以开发票吗？', '如需发票，请在订单备注或联系门店说明开票抬头、税号和金额。具体开票类型以门店支持范围为准。', '订单服务', '发票,开票,抬头,税号,金额', 1, 29, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(30, '支付后还能修改地址吗？', '若订单未取件，可以在联系门店后修改取送地址；已安排配送或已完成取件的订单，需要由门店确认是否可调整。', '订单服务', '修改地址,支付后,取送地址,配送,门店确认', 1, 30, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(31, 'AI客服回答不准确怎么办？', '如果 AI 客服答案和订单实际情况不一致，请以订单详情、门店通知和人工客服确认为准。你也可以换一种问法继续咨询。', 'AI客服', 'AI客服,不准确,人工客服,订单详情,门店通知', 1, 31, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00'),
(32, '知识库没有的问题谁来回答？', '知识库没有命中的问题会自动转由 OpenAI 回答。若后端未配置 OPENAI_API_KEY，系统会给出兜底提示，避免影响页面使用。', 'AI客服', '知识库,OpenAI,OPENAI_API_KEY,兜底,回答', 1, 32, 0, '2026-03-19 00:20:00', '2026-03-19 00:20:00')
ON DUPLICATE KEY UPDATE
  `question` = VALUES(`question`),
  `answer` = VALUES(`answer`),
  `category` = VALUES(`category`),
  `keywords` = VALUES(`keywords`),
  `status` = VALUES(`status`),
  `sort_order` = VALUES(`sort_order`),
  `updated_at` = VALUES(`updated_at`);
